set session characteristics as transaction read write;
set default_transaction_read_only = off;

-- Sanity check: tenant e admin user precisam existir (rode 0002 antes)
do $$
begin
  if not exists (select 1 from tenants where id = '11111111-1111-1111-1111-111111111111'::uuid) then
    raise exception 'Tenant FGCoop não encontrado. Rode 0002_seed_tenant_and_admin.sql antes.';
  end if;
  if not exists (select 1 from auth.users where id = 'aaaaaaaa-aaaa-aaaa-aaaa-aaaaaaaaaaaa'::uuid) then
    raise exception 'Admin user não encontrado. Rode 0002_seed_tenant_and_admin.sql antes.';
  end if;
end $$;

